import{_ as a,o as s,c as e,ae as l}from"./chunks/framework.C7FLYIpo.js";const k=JSON.parse('{"title":"게이트웨이 소유 페어링","description":"iOS 및 기타 원격 노드를 위한 게이트웨이 소유 노드 페어링 (옵션 B)","frontmatter":{"title":"게이트웨이 소유 페어링","description":"iOS 및 기타 원격 노드를 위한 게이트웨이 소유 노드 페어링 (옵션 B)"},"headers":[],"relativePath":"gateway/pairing.md","filePath":"gateway/pairing.md","lastUpdated":null}'),o={name:"gateway/pairing.md"};function n(t,i,d,r,p,h){return s(),e("div",null,[...i[0]||(i[0]=[l(`<h1 id="게이트웨이-소유-페어링-옵션-b" tabindex="-1">게이트웨이 소유 페어링 (옵션 B) <a class="header-anchor" href="#게이트웨이-소유-페어링-옵션-b" aria-label="Permalink to &quot;게이트웨이 소유 페어링 (옵션 B)&quot;">​</a></h1><p>게이트웨이 소유 페어링에서 <strong>게이트웨이</strong>는 어떤 노드가 참여할 수 있는지에 대한 신뢰 소스입니다. UI(macOS 앱, 미래 클라이언트)는 보류 중인 요청을 승인하거나 거부하는 프론트엔드일 뿐입니다.</p><p><strong>중요:</strong> WS 노드는 <code>connect</code> 중에 <strong>기기 페어링</strong> (역할 <code>node</code>)을 사용합니다. <code>node.pair.*</code>는 별도의 페어링 스토어이며 WS 핸드셰이크를 게이팅하지 <strong>않습니다</strong>. 명시적으로 <code>node.pair.*</code>를 호출하는 클라이언트만 이 흐름을 사용합니다.</p><h2 id="개념" tabindex="-1">개념 <a class="header-anchor" href="#개념" aria-label="Permalink to &quot;개념&quot;">​</a></h2><ul><li><strong>보류 중인 요청</strong>: 노드가 참여를 요청했으며 승인이 필요합니다.</li><li><strong>페어링된 노드</strong>: 발급된 인증 토큰이 있는 승인된 노드.</li><li><strong>전송</strong>: 게이트웨이 WS 엔드포인트는 요청을 전달하지만 멤버십을 결정하지 않습니다. (레거시 TCP 브리지 지원이 제거되었습니다.)</li></ul><h2 id="페어링-작동-방식" tabindex="-1">페어링 작동 방식 <a class="header-anchor" href="#페어링-작동-방식" aria-label="Permalink to &quot;페어링 작동 방식&quot;">​</a></h2><ol><li>노드가 게이트웨이 WS에 연결하고 페어링을 요청합니다.</li><li>게이트웨이는 <strong>보류 중인 요청</strong>을 저장하고 <code>node.pair.requested</code>를 내보냅니다.</li><li>요청을 승인하거나 거부합니다 (CLI 또는 UI).</li><li>승인 시 게이트웨이는 <strong>새 토큰</strong>을 발급합니다 (토큰은 재페어링 시 순환됩니다).</li><li>노드는 토큰을 사용하여 재연결하며 이제 &quot;페어링됨&quot; 상태가 됩니다.</li></ol><p>보류 중인 요청은 <strong>5분</strong> 후 자동으로 만료됩니다.</p><h2 id="cli-워크플로우-헤드리스-친화적" tabindex="-1">CLI 워크플로우 (헤드리스 친화적) <a class="header-anchor" href="#cli-워크플로우-헤드리스-친화적" aria-label="Permalink to &quot;CLI 워크플로우 (헤드리스 친화적)&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nodes</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pending</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nodes</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> approve</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">requestI</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">d</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nodes</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> reject</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">requestI</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">d</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nodes</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> status</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nodes</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> rename</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --node</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">id</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">|</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">name</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">|</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ip</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt; </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">--name</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Living Room iPad&quot;</span></span></code></pre></div><p><code>nodes status</code>는 페어링된/연결된 노드와 해당 기능을 표시합니다.</p><h2 id="api-표면-게이트웨이-프로토콜" tabindex="-1">API 표면 (게이트웨이 프로토콜) <a class="header-anchor" href="#api-표면-게이트웨이-프로토콜" aria-label="Permalink to &quot;API 표면 (게이트웨이 프로토콜)&quot;">​</a></h2><p>이벤트:</p><ul><li><code>node.pair.requested</code> — 새 보류 중인 요청이 생성될 때 내보내집니다.</li><li><code>node.pair.resolved</code> — 요청이 승인/거부/만료될 때 내보내집니다.</li></ul><p>메서드:</p><ul><li><code>node.pair.request</code> — 보류 중인 요청을 생성하거나 재사용합니다.</li><li><code>node.pair.list</code> — 보류 중 + 페어링된 노드를 나열합니다 (<code>operator.pairing</code>).</li><li><code>node.pair.approve</code> — 보류 중인 요청을 승인합니다 (토큰 발급).</li><li><code>node.pair.reject</code> — 보류 중인 요청을 거부합니다.</li><li><code>node.pair.verify</code> — <code>{ nodeId, token }</code>을 확인합니다.</li></ul><p>참고 사항:</p><ul><li><code>node.pair.request</code>는 노드별로 멱등성을 가집니다: 반복 호출은 동일한 보류 중인 요청을 반환합니다.</li><li>동일한 보류 중인 노드에 대한 반복 요청은 저장된 노드 메타데이터와 오퍼레이터 가시성을 위한 최신 허용 목록 선언 명령 스냅샷도 새로 고칩니다.</li><li>승인은 <strong>항상</strong> 새 토큰을 생성합니다; <code>node.pair.request</code>에서 토큰은 반환되지 않습니다.</li><li>요청에는 자동 승인 흐름에 대한 힌트로 <code>silent: true</code>가 포함될 수 있습니다.</li><li><code>node.pair.approve</code>는 추가 승인 범위를 적용하기 위해 보류 중인 요청의 선언된 명령을 사용합니다: <ul><li>명령 없는 요청: <code>operator.pairing</code></li><li>exec가 아닌 명령 요청: <code>operator.pairing</code> + <code>operator.write</code></li><li><code>system.run</code> / <code>system.run.prepare</code> / <code>system.which</code> 요청: <code>operator.pairing</code> + <code>operator.admin</code></li></ul></li></ul><p>중요:</p><ul><li>노드 페어링은 신뢰/신원 흐름 플러스 토큰 발급입니다.</li><li>노드별로 라이브 노드 명령 표면을 <strong>핀</strong>하지 않습니다.</li><li>라이브 노드 명령은 게이트웨이의 전역 노드 명령 정책(<code>gateway.nodes.allowCommands</code> / <code>denyCommands</code>)이 적용된 후 노드가 연결 시 선언하는 것에서 옵니다.</li><li>노드별 <code>system.run</code> 허용/요청 정책은 페어링 레코드가 아닌 <code>exec.approvals.node.*</code>의 노드에 있습니다.</li></ul><h2 id="노드-명령-게이팅-2026-3-31" tabindex="-1">노드 명령 게이팅 (2026.3.31+) <a class="header-anchor" href="#노드-명령-게이팅-2026-3-31" aria-label="Permalink to &quot;노드 명령 게이팅 (2026.3.31+)&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p><strong>호환성을 깨는 변경:</strong> <code>2026.3.31</code>부터 노드 명령은 노드 페어링이 승인될 때까지 비활성화됩니다. 기기 페어링만으로는 선언된 노드 명령을 노출하기에 더 이상 충분하지 않습니다.</p></div><p>노드가 처음 연결될 때 페어링이 자동으로 요청됩니다. 페어링 요청이 승인될 때까지 해당 노드의 모든 보류 중인 노드 명령은 필터링되어 실행되지 않습니다. 페어링 승인을 통해 신뢰가 확립되면 노드의 선언된 명령은 정상 명령 정책에 따라 사용 가능해집니다.</p><p>이는 다음을 의미합니다:</p><ul><li>이전에 명령을 노출하기 위해 기기 페어링만 사용했던 노드는 이제 노드 페어링을 완료해야 합니다.</li><li>페어링 승인 전에 대기열에 있던 명령은 연기되지 않고 삭제됩니다.</li></ul><h2 id="노드-이벤트-신뢰-경계-2026-3-31" tabindex="-1">노드 이벤트 신뢰 경계 (2026.3.31+) <a class="header-anchor" href="#노드-이벤트-신뢰-경계-2026-3-31" aria-label="Permalink to &quot;노드 이벤트 신뢰 경계 (2026.3.31+)&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p><strong>호환성을 깨는 변경:</strong> 노드 발생 실행은 이제 축소된 신뢰할 수 있는 표면에 유지됩니다.</p></div><p>노드 발생 요약 및 관련 세션 이벤트는 의도된 신뢰할 수 있는 표면으로 제한됩니다. 이 강화는 노드 이벤트가 노드의 신뢰 경계가 허용하는 것 이상의 호스트 수준 도구 액세스로 에스컬레이션할 수 없도록 보장합니다.</p><h2 id="자동-승인-macos-앱" tabindex="-1">자동 승인 (macOS 앱) <a class="header-anchor" href="#자동-승인-macos-앱" aria-label="Permalink to &quot;자동 승인 (macOS 앱)&quot;">​</a></h2><p>macOS 앱은 선택적으로 <strong>자동 승인</strong>을 시도할 수 있습니다:</p><ul><li>요청이 <code>silent</code>로 표시된 경우, 그리고</li><li>앱이 동일한 사용자를 사용하여 게이트웨이 호스트에 SSH 연결을 확인할 수 있는 경우.</li></ul><p>자동 승인이 실패하면 정상적인 &quot;승인/거부&quot; 프롬프트로 폴백합니다.</p><h2 id="저장-로컬-비공개" tabindex="-1">저장 (로컬, 비공개) <a class="header-anchor" href="#저장-로컬-비공개" aria-label="Permalink to &quot;저장 (로컬, 비공개)&quot;">​</a></h2><p>페어링 상태는 게이트웨이 상태 디렉터리 아래에 저장됩니다 (기본값 <code>~/.openclaw</code>):</p><ul><li><code>~/.openclaw/nodes/paired.json</code></li><li><code>~/.openclaw/nodes/pending.json</code></li></ul><p><code>OPENCLAW_STATE_DIR</code>을 재정의하면 <code>nodes/</code> 폴더가 그것과 함께 이동합니다.</p><p>보안 참고 사항:</p><ul><li>토큰은 시크릿입니다; <code>paired.json</code>을 민감한 것으로 취급하십시오.</li><li>토큰을 순환하려면 재승인(또는 노드 항목 삭제)이 필요합니다.</li></ul><h2 id="전송-동작" tabindex="-1">전송 동작 <a class="header-anchor" href="#전송-동작" aria-label="Permalink to &quot;전송 동작&quot;">​</a></h2><ul><li>전송은 <strong>상태 없음</strong>입니다; 멤버십을 저장하지 않습니다.</li><li>게이트웨이가 오프라인이거나 페어링이 비활성화된 경우 노드는 페어링할 수 없습니다.</li><li>게이트웨이가 원격 모드에 있는 경우 페어링은 여전히 원격 게이트웨이의 스토어에 대해 발생합니다.</li></ul>`,40)])])}const g=a(o,[["render",n]]);export{k as __pageData,g as default};
